import React, { useState } from 'react';
import axios from 'axios';
import Dropzone from 'react-dropzone';
import './App.css';

function App() {
  const [file, setFile] = useState(null);
  const [targetColumn, setTargetColumn] = useState('diagnosis');
  const [dropColumns, setDropColumns] = useState('id');
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const onDrop = (acceptedFiles) => {
    setFile(acceptedFiles[0]);
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!file) {
      setError('Please select a CSV file');
      return;
    }

    setLoading(true);
    setError('');
    setResults(null);

    const formData = new FormData();
    formData.append('file', file);
    formData.append('targetColumn', targetColumn);
    formData.append('dropColumns', dropColumns);

    try {
      const response = await axios.post('http://localhost:5000/predict', formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });
      setResults(response.data.results);
    } catch (err) {
      setError(err.response?.data?.error || 'Network Error: Could not connect to the server');
    } finally {
      setLoading(false);
    }
  };

  const parseResults = (resultsText) => {
    if (!resultsText) return { accuracies: [], bestModel: '', bestAccuracy: 0 };

    const lines = resultsText.split('\n');
    const accuracies = [];
    let bestModel = '';
    let bestAccuracy = 0;

    lines.forEach((line) => {
      line = line.trim();
      if (line.includes('Accuracy:') && !line.includes('Best Model:')) {
        const [namePart, accuracyPart] = line.split(' Accuracy: ');
        const name = namePart.trim();
        const accuracy = parseFloat(accuracyPart);
        if (!isNaN(accuracy)) {
          accuracies.push({ name, accuracy });
        }
      } else if (line.includes('Error:') && !line.includes('Best Model:')) {
        const [namePart, errorPart] = line.split(' Error: ');
        const name = namePart.trim();
        accuracies.push({ name, accuracy: 'Error', error: errorPart });
      } else if (line.startsWith('Best Model:')) {
        const parts = line.replace('Best Model:', '').split(' with Accuracy: ');
        bestModel = parts[0].trim();
        bestAccuracy = parseFloat(parts[1]);
      }
    });

    // Fallback to calculate best model if not explicitly provided
    if (!bestModel && accuracies.length > 0) {
      const validAccuracies = accuracies.filter(a => a.accuracy !== 'Error');
      if (validAccuracies.length > 0) {
        const best = validAccuracies.reduce((prev, curr) =>
          curr.accuracy > prev.accuracy ? curr : prev
        );
        bestModel = best.name;
        bestAccuracy = best.accuracy;
      }
    }

    return { accuracies, bestModel, bestAccuracy };
  };

  const { accuracies, bestModel, bestAccuracy } = parseResults(results);

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 p-6">
      <div className="max-w-5xl mx-auto bg-white rounded-xl shadow-lg overflow-hidden">
        <header className="bg-indigo-600 text-white p-6">
          <h1 className="text-3xl font-bold">Machine Learning Classifier</h1>
          <p className="mt-2 text-indigo-100">Upload a CSV file to compare multiple ML models</p>
        </header>

        <main className="p-6 md:p-8">
          <div className="flex flex-col md:flex-row gap-8">
            <form onSubmit={handleSubmit} className="flex-1 space-y-6">
              <div className="space-y-1">
                <label className="block text-sm font-medium text-gray-700">Dataset</label>
                <Dropzone
                  onDrop={onDrop}
                  accept={{ 'text/csv': ['.csv'] }}
                  multiple={false}
                >
                  {({ getRootProps, getInputProps }) => (
                    <div 
                      {...getRootProps()} 
                      className="border-2 border-dashed border-indigo-300 rounded-lg p-6 transition-colors hover:border-indigo-500 bg-indigo-50 text-center cursor-pointer"
                    >
                      <input {...getInputProps()} />
                      {file ? (
                        <div>
                          <div className="text-indigo-600 font-medium mb-1">File selected:</div>
                          <div className="text-gray-700">{file.name}</div>
                        </div>
                      ) : (
                        <div>
                          <div className="text-indigo-600 font-medium mb-1">Drop CSV file here</div>
                          <p className="text-gray-500 text-sm">or click to browse files</p>
                        </div>
                      )}
                    </div>
                  )}
                </Dropzone>
              </div>

              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Target Column
                  </label>
                  <input
                    type="text"
                    value={targetColumn}
                    onChange={(e) => setTargetColumn(e.target.value)}
                    placeholder="e.g., diagnosis"
                    className="w-full p-3 border border-gray-300 rounded-md focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Columns to Drop (comma-separated)
                  </label>
                  <input
                    type="text"
                    value={dropColumns}
                    onChange={(e) => setDropColumns(e.target.value)}
                    placeholder="e.g., id"
                    className="w-full p-3 border border-gray-300 rounded-md focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500"
                  />
                </div>
              </div>

              <button
                type="submit"
                disabled={loading}
                className="w-full py-3 px-4 bg-indigo-600 hover:bg-indigo-700 text-white font-medium rounded-md shadow-sm transition-colors disabled:opacity-70"
              >
                {loading ? (
                  <span className="flex items-center justify-center">
                    <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    Processing...
                  </span>
                ) : (
                  'Run Models'
                )}
              </button>

              {error && (
                <div className="p-4 bg-red-50 border-l-4 border-red-500 text-red-700 rounded">
                  <div className="flex">
                    <div className="flex-shrink-0">
                      <svg className="h-5 w-5 text-red-500" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                      </svg>
                    </div>
                    <div className="ml-3">
                      <p className="text-sm">{error}</p>
                    </div>
                  </div>
                </div>
              )}
            </form>

            {results && (
              <div className="flex-1">
                <div className="bg-white rounded-lg border border-gray-200 shadow-sm">
                  <div className="border-b border-gray-200 bg-gray-50 p-4">
                    <h2 className="text-lg font-medium text-gray-900">Model Performance</h2>
                  </div>
                  <div className="p-4">
                    <div className="overflow-x-auto">
                      <table className="min-w-full divide-y divide-gray-200">
                        <thead className="bg-gray-50">
                          <tr>
                            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                              Model
                            </th>
                            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                              Accuracy
                            </th>
                          </tr>
                        </thead>
                        <tbody className="bg-white divide-y divide-gray-200">
                          {accuracies.map((model, index) => (
                            <tr
                              key={index}
                              className={model.name === bestModel ? 'bg-indigo-50' : ''}
                            >
                              <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                                {model.name === bestModel && (
                                  <span className="inline-flex items-center mr-2">
                                    <svg className="h-4 w-4 text-indigo-600" viewBox="0 0 20 20" fill="currentColor">
                                      <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                                    </svg>
                                  </span>
                                )}
                                {model.name}
                              </td>
                              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                                {model.accuracy === 'Error' ? (
                                  <span className="text-red-600">{model.error}</span>
                                ) : (
                                  <span className={model.name === bestModel ? 'font-medium text-indigo-700' : ''}>
                                    {(model.accuracy * 100).toFixed(2)}%
                                  </span>
                                )}
                              </td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>

                    {bestModel && (
                      <div className="mt-6 p-4 border border-indigo-200 rounded-lg bg-indigo-50">
                        <div className="flex items-center">
                          <div className="flex-shrink-0 bg-indigo-100 rounded-full p-2">
                            <svg className="h-6 w-6 text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                            </svg>
                          </div>
                          <div className="ml-3">
                            <h3 className="text-sm font-medium text-indigo-800">Best Performing Model</h3>
                            <div className="mt-1 text-sm text-indigo-700">
                              <span className="font-semibold">{bestModel}</span> with <span className="font-semibold">{(bestAccuracy * 100).toFixed(2)}%</span> accuracy
                            </div>
                          </div>
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            )}
          </div>
        </main>
      </div>
    </div>
  );
}

export default App;
